INSERT INTO roles (id, name_en, name_ua, description_en, description_ua, type, edition, image_url, meta)
VALUES
  ('acrobat', 'Acrobat', 'Акробат', 'Each night*, if either good living neighbour is drunk or poisoned, you die.', 'Each night*, if either good living neighbour is drunk or poisoned, you die.', 'outsider', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/acrobat.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":44,"otherNightReminder":"If a good living neighbour is drunk or poisoned, the Acrobat player dies.","setup":false,"reminders":["Dead"]}'),
  ('alchemist', 'Alchemist', 'Алхімік', 'You have a not-in-play Minion ability.', 'You have a not-in-play Minion ability.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/alchemist.png', '{"firstNight":4,"firstNightReminder":"Show the Alchemist a not-in-play Minion token","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('alhadikhia', 'Al-Hadikhia', 'Аль-Хадіхія', 'Each night*, choose 3 players (all players learn who): each silently chooses to live or die, but if all live, all die.', 'Each night*, choose 3 players (all players learn who): each silently chooses to live or die, but if all live, all die.', 'demon', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/alhadikhia.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":36,"otherNightReminder":"The Al-Hadikhia chooses 3 players. Announce the first player, wake them to nod yes to live or shake head no to die, kill or resurrect accordingly, then put to sleep and announce the next player. If all 3 are alive after this, all 3 die.","setup":false,"reminders":["1","2","3","Chose death","Chose life"]}'),
  ('amnesiac', 'Amnesiac', 'Амнезійник', 'You do not know what your ability is. Each day, privately guess what it is: you learn how accurate you are.', 'You do not know what your ability is. Each day, privately guess what it is: you learn how accurate you are.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/amnesiac.png', '{"firstNight":36,"firstNightReminder":"Decide the Amnesiac''s entire ability. If the Amnesiac''s ability causes them to wake tonight: Wake the Amnesiac and run their ability.","otherNight":54,"otherNightReminder":"If the Amnesiac''s ability causes them to wake tonight: Wake the Amnesiac and run their ability.","setup":false,"reminders":["?"]}'),
  ('angel', 'Angel', 'Ангел', 'Something bad might happen to whoever is most responsible for the death of a new player.', 'Something bad might happen to whoever is most responsible for the death of a new player.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/angel.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Protect","Something Bad"]}'),
  ('apprentice', 'Apprentice', 'Учень', 'On your 1st night, you gain a Townsfolk ability (if good), or a Minion ability (if evil).', 'On your 1st night, you gain a Townsfolk ability (if good), or a Minion ability (if evil).', 'traveller', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/apprentice.png', '{"firstNight":null,"firstNightReminder":"Show the Apprentice the ''You are'' card, then a Townsfolk or Minion token. In the Grimoire, replace the Apprentice token with that character token, and put the Apprentice''s ''Is the Apprentice'' reminder by that character token.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Is the Apprentice"]}'),
  ('artist', 'Artist', 'Художник', 'Once per game, during the day, privately ask the Storyteller any yes/no question.', 'Once per game, during the day, privately ask the Storyteller any yes/no question.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/artist.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["No ability"]}'),
  ('assassin', 'Assassin', 'Асасин', 'Once per game, at night*, choose a player: they die, even if for some reason they could not.', 'Once per game, at night*, choose a player: they die, even if for some reason they could not.', 'minion', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/assassin.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":41,"otherNightReminder":"If the Assassin has not yet used their ability: The Assassin either shows the ''no'' head signal, or points to a player. That player dies.","setup":false,"reminders":["Dead","No ability"]}'),
  ('atheist', 'Atheist', 'Атеїст', 'The Storyteller can break the game rules & if executed, good wins, even if you are dead. [No evil characters]', 'The Storyteller can break the game rules & if executed, good wins, even if you are dead. [No evil characters]', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/atheist.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":true,"reminders":[]}'),
  ('balloonist', 'Balloonist', 'Повітроплавець', 'Each night, you learn 1 player of each character type, until there are no more types to learn. [+1 Outsider]', 'Each night, you learn 1 player of each character type, until there are no more types to learn. [+1 Outsider]', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/balloonist.png', '{"firstNight":51,"firstNightReminder":"Choose a character type. Point to a player whose character is of that type. Place the Balloonist''s Seen reminder next to that character.","otherNight":69,"otherNightReminder":"Choose a character type that does not yet have a Seen reminder next to a character of that type. Point to a player whose character is of that type, if there are any. Place the Balloonist''s Seen reminder next to that character.","setup":true,"reminders":["Seen Townsfolk","Seen Outsider","Seen Minion","Seen Demon","Seen Traveller"]}'),
  ('banshee', 'Banshee', 'Банші', 'If the Demon kills you, all players learn this. From now on, you may nominate twice per day and vote twice per nomination.', 'If the Demon kills you, all players learn this. From now on, you may nominate twice per day and vote twice per nomination.', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/banshee.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":49,"otherNightReminder":"Announce that the Banshee has died.","setup":false,"reminders":["Has Ability"]}'),
  ('barber', 'Barber', 'Цирульник', 'If you died today or tonight, the Demon may choose 2 players (not another Demon) to swap characters.', 'If you died today or tonight, the Demon may choose 2 players (not another Demon) to swap characters.', 'outsider', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/barber.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":46,"otherNightReminder":"If the Barber died today: Wake the Demon. Show the ''This character selected you'' card, then Barber token. The Demon either shows a ''no'' head signal, or points to 2 players. If they chose players: Swap the character tokens. Wake each player. Show ''You are'', then their new character token.","setup":false,"reminders":["Haircuts tonight"]}'),
  ('barista', 'Barista', 'Бариста', 'Each night, until dusk, 1) a player becomes sober, healthy and gets true info, or 2) their ability works twice. They learn which.', 'Each night, until dusk, 1) a player becomes sober, healthy and gets true info, or 2) their ability works twice. They learn which.', 'traveller', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/barista.png', '{"firstNight":null,"firstNightReminder":"Choose a player, wake them and tell them which Barista power is affecting them. Treat them accordingly (sober/healthy/true info or activate their ability twice).","otherNight":null,"otherNightReminder":"Choose a player, wake them and tell them which Barista power is affecting them. Treat them accordingly (sober/healthy/true info or activate their ability twice).","setup":false,"reminders":["Sober & Healthy","Ability twice"]}'),
  ('baron', 'Baron', 'Барон', 'There are extra Outsiders in play. [+2 Outsiders]', 'There are extra Outsiders in play. [+2 Outsiders]', 'minion', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/baron.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":true,"reminders":[]}'),
  ('beggar', 'Beggar', 'Жебрак', 'You must use a vote token to vote. Dead players may choose to give you theirs. If so, you learn their alignment. You are sober & healthy.', 'You must use a vote token to vote. Dead players may choose to give you theirs. If so, you learn their alignment. You are sober & healthy.', 'traveller', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/beggar.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('bishop', 'Bishop', 'Єпископ', 'Only the Storyteller can nominate. At least 1 opposite player must be nominated each day.', 'Only the Storyteller can nominate. At least 1 opposite player must be nominated each day.', 'traveller', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/bishop.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Nominate good","Nominate evil"]}'),
  ('bonecollector', 'Bone Collector', 'Bone Collector', 'Once per game, at night, choose a dead player: they regain their ability until dusk.', 'Once per game, at night, choose a dead player: they regain their ability until dusk.', 'traveller', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/bonecollector.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":"The Bone Collector either shakes their head no or points at any dead player. If they pointed at any dead player, put the Bone Collector''s ''Has Ability'' reminder by the chosen player''s character token. (They may need to be woken tonight to use it.)","setup":false,"reminders":["No ability","Has ability"]}'),
  ('boomdandy', 'Boomdandy', 'Бум-Денді', 'If you are executed, all but 3 players die. 1 minute later, the player with the most players pointing at them dies.', 'If you are executed, all but 3 players die. 1 minute later, the player with the most players pointing at them dies.', 'minion', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/boomdandy.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('bootlegger', 'Bootlegger', 'Bootlegger', 'This script has homebrew characters or rules.', 'This script has homebrew characters or rules.', 'fabled', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/bootlegger.png', '{"firstNight":null,"firstNightReminder":"Announce the Bootlegger is in play and inform the group of all homebrew characters and/or rules you are using in this game. ","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('bountyhunter', 'Bounty Hunter', 'Мисливець за головами', 'You start knowing 1 evil player. If the player you know dies, you learn another evil player tonight. [1 Townsfolk is evil]', 'You start knowing 1 evil player. If the player you know dies, you learn another evil player tonight. [1 Townsfolk is evil]', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/bountyhunter.png', '{"firstNight":54,"firstNightReminder":"Point to 1 evil player. Wake the townsfolk who is evil and show them the ''You are'' card and the thumbs down evil sign.","otherNight":72,"otherNightReminder":"If the known evil player has died, point to another evil player. ","setup":true,"reminders":["Known"]}'),
  ('buddhist', 'Buddhist', 'Будист', 'For the first 2 minutes of each day, veteran players may not talk.', 'For the first 2 minutes of each day, veteran players may not talk.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/buddhist.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('bureaucrat', 'Bureaucrat', 'Бюрократ', 'Each night, choose a player (not yourself): their vote counts as 3 votes tomorrow.', 'Each night, choose a player (not yourself): their vote counts as 3 votes tomorrow.', 'traveller', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/bureaucrat.png', '{"firstNight":null,"firstNightReminder":"The Bureaucrat points to a player. Put the Bureaucrat''s ''3 votes'' reminder by the chosen player''s character token.","otherNight":null,"otherNightReminder":"The Bureaucrat points to a player. Put the Bureaucrat''s ''3 votes'' reminder by the chosen player''s character token.","setup":false,"reminders":["3 votes"]}'),
  ('butcher', 'Butcher', 'М''ясник', 'Each day, after the 1st execution, you may nominate again.', 'Each day, after the 1st execution, you may nominate again.', 'traveller', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/butcher.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('butler', 'Butler', 'Дворецький', 'Each night, choose a player (not yourself): tomorrow, you may only vote if they are voting too.', 'Each night, choose a player (not yourself): tomorrow, you may only vote if they are voting too.', 'outsider', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/butler.png', '{"firstNight":43,"firstNightReminder":"The Butler points to a player. Mark that player as ''Master''.","otherNight":75,"otherNightReminder":"The Butler points to a player. Mark that player as ''Master''.","setup":false,"reminders":["Master"]}'),
  ('cannibal', 'Cannibal', 'Канібал', 'You have the ability of the recently killed executee. If they are evil, you are poisoned until a good player dies by execution.', 'You have the ability of the recently killed executee. If they are evil, you are poisoned until a good player dies by execution.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/cannibal.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Poisoned","Died today"]}'),
  ('cerenovus', 'Cerenovus', 'Церенов', 'Each night, choose a player & a good character: they are “mad” they are this character tomorrow, or might be executed.', 'Each night, choose a player & a good character: they are “mad” they are this character tomorrow, or might be executed.', 'minion', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/cerenovus.png', '{"firstNight":28,"firstNightReminder":"The Cerenovus points to a player, then to a character on their sheet. Wake that player. Show the ''This character selected you'' card, then the Cerenovus token. Show the selected character token. If the player is not mad about being that character tomorrow, they can be executed.","otherNight":15,"otherNightReminder":"The Cerenovus points to a player, then to a character on their sheet. Wake that player. Show the ''This character selected you'' card, then the Cerenovus token. Show the selected character token. If the player is not mad about being that character tomorrow, they can be executed.","setup":false,"reminders":["Mad"]}'),
  ('chambermaid', 'Chambermaid', 'Покоївка', 'Each night, choose 2 alive players (not yourself): you learn how many woke tonight due to their ability.', 'Each night, choose 2 alive players (not yourself): you learn how many woke tonight due to their ability.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/chambermaid.png', '{"firstNight":61,"firstNightReminder":"The Chambermaid points to two players. Show the number signal (0, 1, 2, …) for how many of those players wake tonight for their ability.","otherNight":79,"otherNightReminder":"The Chambermaid points to two players. Show the number signal (0, 1, 2, …) for how many of those players wake tonight for their ability.","setup":false,"reminders":[]}'),
  ('chef', 'Chef', 'Кухар', 'You start knowing how many pairs of evil players there are.', 'You start knowing how many pairs of evil players there are.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/chef.png', '{"firstNight":40,"firstNightReminder":"Show the finger signal (0, 1, 2, …) for the number of pairs of neighbouring evil players.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('choirboy', 'Choirboy', 'Хористик', 'If the Demon kills the King, you learn which player is the Demon. [+ the King]', 'If the Demon kills the King, you learn which player is the Demon. [+ the King]', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/choirboy.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":51,"otherNightReminder":"If the King was killed by the Demon, wake the Choirboy and point to the Demon player.","setup":true,"reminders":[]}'),
  ('clockmaker', 'Clockmaker', 'Годинникар', 'You start knowing how many steps from the Demon to its nearest Minion.', 'You start knowing how many steps from the Demon to its nearest Minion.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/clockmaker.png', '{"firstNight":45,"firstNightReminder":"Show the hand signal for the number (1, 2, 3, etc.) of places from Demon to closest Minion.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('courtier', 'Courtier', 'Придворний', 'Once per game, at night, choose a character: they are drunk for 3 nights & 3 days.', 'Once per game, at night, choose a character: they are drunk for 3 nights & 3 days.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/courtier.png', '{"firstNight":22,"firstNightReminder":"The Courtier either shows a ''no'' head signal, or points to a character on the sheet. If the Courtier used their ability: If that character is in play, that player is drunk.","otherNight":8,"otherNightReminder":"Reduce the remaining number of days the marked player is poisoned. If the Courtier has not yet used their ability: The Courtier either shows a ''no'' head signal, or points to a character on the sheet. If the Courtier used their ability: If that character is in play, that player is drunk.","setup":false,"reminders":["Drunk 3","Drunk 2","Drunk 1","No ability"]}'),
  ('cultleader', 'Cult Leader', 'Лідер Культу', 'Each night, you become the alignment of an alive neighbour. If all good players choose to join your cult, your team wins.', 'Each night, you become the alignment of an alive neighbour. If all good players choose to join your cult, your team wins.', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/cultleader.png', '{"firstNight":56,"firstNightReminder":"If the cult leader changed alignment, show them the thumbs up good signal of the thumbs down evil signal accordingly.","otherNight":74,"otherNightReminder":"If the cult leader changed alignment, show them the thumbs up good signal of the thumbs down evil signal accordingly.","setup":false,"reminders":[]}'),
  ('damsel', 'Damsel', 'Панянка', 'All Minions know you are in play. If a Minion publicly guesses you (once), your team loses.', 'All Minions know you are in play. If a Minion publicly guesses you (once), your team loses.', 'outsider', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/damsel.png', '{"firstNight":35,"firstNightReminder":"Wake all the Minions, show them the ''This character selected you'' card and the Damsel token.","otherNight":53,"otherNightReminder":"If selected by the Huntsman, wake the Damsel, show ''You are'' card and a not-in-play Townsfolk token.","setup":false,"reminders":["Guess used"]}'),
  ('deviant', 'Deviant', 'Девіант', 'If you were funny today, you cannot die by exile.', 'If you were funny today, you cannot die by exile.', 'traveller', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/deviant.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('devilsadvocate', 'Devil''s Advocate', 'Адвокат Диявола', 'Each night, choose a living player (different to last night): if executed tomorrow, they don''t die.', 'Each night, choose a living player (different to last night): if executed tomorrow, they don''t die.', 'minion', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/devilsadvocate.png', '{"firstNight":25,"firstNightReminder":"The Devil’s Advocate points to a living player. That player survives execution tomorrow.","otherNight":13,"otherNightReminder":"The Devil’s Advocate points to a living player, different from the previous night. That player survives execution tomorrow.","setup":false,"reminders":["Survives execution"]}'),
  ('djinn', 'Djinn', 'Джин', 'Use the Djinn''s special rule. All players know what it is.', 'Use the Djinn''s special rule. All players know what it is.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/djinn.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('doomsayer', 'Doomsayer', 'Doomsayer', 'If 4 or more players live, each living player may publicly choose (once per game) that a player of their own alignment dies.', 'If 4 or more players live, each living player may publicly choose (once per game) that a player of their own alignment dies.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/doomsayer.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('dreamer', 'Dreamer', 'Сновида', 'Each night, choose a player (not yourself or Travellers): you learn 1 good and 1 evil character, 1 of which is correct.', 'Each night, choose a player (not yourself or Travellers): you learn 1 good and 1 evil character, 1 of which is correct.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/dreamer.png', '{"firstNight":46,"firstNightReminder":"The Dreamer points to a player. Show 1 good and 1 evil character token; one of these is correct.","otherNight":63,"otherNightReminder":"The Dreamer points to a player. Show 1 good and 1 evil character token; one of these is correct.","setup":false,"reminders":[]}'),
  ('drunk', 'Drunk', 'П''яниця', 'You do not know you are the Drunk. You think you are a Townsfolk character, but you are not.', 'You do not know you are the Drunk. You think you are a Townsfolk character, but you are not.', 'outsider', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/drunk.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":true,"reminders":[]}'),
  ('duchess', 'Duchess', 'Герцогиня', 'Each day, 3 players may choose to visit you. At night*, each visitor learns how many visitors are evil, but 1 gets false info.', 'Each day, 3 players may choose to visit you. At night*, each visitor learns how many visitors are evil, but 1 gets false info.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/duchess.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":"Wake each player marked “Visitor” or “False Info” one at a time. Show them the Duchess token, then fingers (1, 2, 3) equaling the number of evil players marked “Visitor” or, if you are waking the player marked “False Info,” show them any number of fingers except the number of evil players marked “Visitor.”","setup":false,"reminders":["Visitor","False Info"]}'),
  ('empath', 'Empath', 'Емпат', 'Each night, you learn how many of your 2 alive neighbours are evil.', 'Each night, you learn how many of your 2 alive neighbours are evil.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/empath.png', '{"firstNight":41,"firstNightReminder":"Show the finger signal (0, 1, 2) for the number of evil alive neighbours of the Empath.","otherNight":60,"otherNightReminder":"Show the finger signal (0, 1, 2) for the number of evil neighbours.","setup":false,"reminders":[]}'),
  ('engineer', 'Engineer', 'Інженер', 'Once per game, at night, choose which Minions or which Demon is in play.', 'Once per game, at night, choose which Minions or which Demon is in play.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/engineer.png', '{"firstNight":16,"firstNightReminder":"The Engineer shows a ''no'' head signal, or points to a Demon or points to the relevant number of Minions. If the Engineer chose characters, replace the Demon or Minions with the choices, then wake the relevant players and show them the You are card and the relevant character tokens.","otherNight":5,"otherNightReminder":"The Engineer shows a ''no'' head signal, or points to a Demon or points to the relevant number of Minions. If the Engineer chose characters, replace the Demon or Minions with the choices, then wake the relevant players and show them the ''You are'' card and the relevant character tokens.","setup":false,"reminders":["No ability"]}'),
  ('eviltwin', 'Evil Twin', 'Злий Близнюк', 'You & an opposing player know each other. If the good player is executed, evil wins. Good can''t win if you both live.', 'You & an opposing player know each other. If the good player is executed, evil wins. Good can''t win if you both live.', 'minion', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/eviltwin.png', '{"firstNight":26,"firstNightReminder":"Wake the Evil Twin and their twin. Confirm that they have acknowledged each other. Point to the Evil Twin. Show their Evil Twin token to the twin player. Point to the twin. Show their character token to the Evil Twin player.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Twin"]}'),
  ('exorcist', 'Exorcist', 'Екзорцист', 'Each night*, choose a player (different to last night): the Demon, if chosen, learns who you are then doesn''t wake tonight.', 'Each night*, choose a player (different to last night): the Demon, if chosen, learns who you are then doesn''t wake tonight.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/exorcist.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":23,"otherNightReminder":"The Exorcist points to a player, different from the previous night. If that player is the Demon: Wake the Demon. Show the Exorcist token. Point to the Exorcist. The Demon does not act tonight.","setup":false,"reminders":["Chosen"]}'),
  ('fanggu', 'Fang Gu', 'Фанг Гу', 'Each night*, choose a player: they die. The 1st Outsider this kills becomes an evil Fang Gu & you die instead. [+1 Outsider]', 'Each night*, choose a player: they die. The 1st Outsider this kills becomes an evil Fang Gu & you die instead. [+1 Outsider]', 'demon', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/fanggu.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":31,"otherNightReminder":"The Fang Gu points to a player. That player dies. Or, if that player was an Outsider and there are no other Fang Gu in play: The Fang Gu dies instead of the chosen player. The chosen player is now an evil Fang Gu. Wake the new Fang Gu. Show the ''You are'' card, then the Fang Gu token. Show the ''You are'' card, then the thumb-down ''evil'' hand sign.","setup":true,"reminders":["Dead","Once"]}'),
  ('farmer', 'Farmer', 'Farmer', 'If you die at night, an alive good player becomes a Farmer.', 'If you die at night, an alive good player becomes a Farmer.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/farmer.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":55,"otherNightReminder":"If a Farmer died tonight, choose another good player and make them the Farmer. Wake this player, show them the ''You are'' card and the Farmer character token.","setup":false,"reminders":[]}'),
  ('fearmonger', 'Fearmonger', 'Страхітник', 'Each night, choose a player. If you nominate & execute them, their team loses. All players know if you choose a new player.', 'Each night, choose a player. If you nominate & execute them, their team loses. All players know if you choose a new player.', 'minion', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/fearmonger.png', '{"firstNight":29,"firstNightReminder":"The Fearmonger points to a player. Place the Fear token next to that player and announce that a new player has been selected with the Fearmonger ability.","otherNight":17,"otherNightReminder":"The Fearmonger points to a player. If different from the previous night, place the Fear token next to that player and announce that a new player has been selected with the Fearmonger ability.","setup":false,"reminders":["Fear"]}'),
