  ('lilmonsta', 'Lil'' Monsta', 'Lil'' Monsta', 'Each night, Minions choose who babysits Lil'' Monsta''s token & "is the Demon". A player dies each night*. [+1 Minion]', 'Each night, Minions choose who babysits Lil'' Monsta''s token & "is the Demon". A player dies each night*. [+1 Minion]', 'demon', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/lilmonsta.png', '{"firstNight":18,"firstNightReminder":"Wake all Minions together, allow them to vote by pointing at who they want to babysit Lil'' Monsta.","otherNight":38,"otherNightReminder":"Wake all Minions together, allow them to vote by pointing at who they want to babysit Lil'' Monsta. Choose a player, that player dies.","setup":true,"reminders":[]}'),
  ('lleech', 'Lleech', 'Ллеч', 'Each night*, choose a player: they die. You start by choosing an alive player: they are poisoned - you die if & only if they die.', 'Each night*, choose a player: they die. You start by choosing an alive player: they are poisoned - you die if & only if they die.', 'demon', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/lleech.png', '{"firstNight":19,"firstNightReminder":"The Lleech points to a player. Place the Poisoned reminder token.","otherNight":37,"otherNightReminder":"The Lleech points to a player. That player dies.","setup":false,"reminders":["Dead","Poisoned"]}'),
  ('lunatic', 'Lunatic', 'Божевільний', 'You think you are a Demon, but you are not. The Demon knows who you are & who you choose at night.', 'You think you are a Demon, but you are not. The Demon knows who you are & who you choose at night.', 'outsider', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/lunatic.png', '{"firstNight":10,"firstNightReminder":"If 7 or more players: Show the Lunatic a number of arbitrary ''Minions'', players equal to the number of Minions in play. Show 3 character tokens of arbitrary good characters. If the token received by the Lunatic is a Demon that would wake tonight: Allow the Lunatic to do the Demon actions. Place their ''attack'' markers. Wake the Demon. Show the Demon’s real character token. Show them the Lunatic player. If the Lunatic attacked players: Show the real demon each marked player. Remove any Lunatic ''attack'' markers.","otherNight":22,"otherNightReminder":"Allow the Lunatic to do the actions of the Demon. Place their ''attack'' markers. If the Lunatic selected players: Wake the Demon. Show the ''attack'' marker, then point to each marked player. Remove any Lunatic ''attack'' markers.","setup":false,"reminders":["Attack 1","Attack 2","Attack 3"]}'),
  ('lycanthrope', 'Lycanthrope', 'Лікантроп', 'Each night*, choose a living player: if good, they die, but they are the only player that can die tonight.', 'Each night*, choose a living player: if good, they die, but they are the only player that can die tonight.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/lycanthrope.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":24,"otherNightReminder":"The Lycanthrope points to a living player: if good, they die and no one else can die tonight.","setup":false,"reminders":["Dead"]}'),
