  ('marionette', 'Marionette', 'Маріонетка', 'You think you are a good character but you are not. The Demon knows who you are. [You neighbour the Demon]', 'You think you are a good character but you are not. The Demon knows who you are. [You neighbour the Demon]', 'minion', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/marionette.png', '{"firstNight":15,"firstNightReminder":"Select one of the good players next to the Demon and place the Is the Marionette reminder token. Wake the Demon and show them the Marionette.","otherNight":null,"otherNightReminder":null,"setup":true,"reminders":[]}'),
