  ('mathematician', 'Mathematician', 'Математик', 'Each night, you learn how many players’ abilities worked abnormally (since dawn) due to another character''s ability.', 'Each night, you learn how many players’ abilities worked abnormally (since dawn) due to another character''s ability.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/mathematician.png', '{"firstNight":62,"firstNightReminder":"Show the hand signal for the number (0, 1, 2, etc.) of players whose ability malfunctioned due to other abilities.","otherNight":80,"otherNightReminder":"Show the hand signal for the number (0, 1, 2, etc.) of players whose ability malfunctioned due to other abilities.","setup":false,"reminders":["Abnormal"]}'),
